"use client";
import React from "react";
import Box from "@mui/material/Box";
import Container from "@mui/material/Container";
import CssBaseline from "@mui/material/CssBaseline";
import {
  createTheme,
  responsiveFontSizes,
  styled,
  ThemeProvider,
} from "@mui/material/styles";
import Toolbar from "@mui/material/Toolbar";
import {
  ChatBar,
  ChatDialog,
  ChatList,
  ChatSettings,
  ChatsHeader,
  ConversationHead,
  MessengerSearch,
} from "./components";
import {
  Content,
  EdgeSidebar,
  EdgeSidebarContent,
  Footer,
  Header,
  InsetAvoidingView,
  InsetSidebar,
  InsetContent,
  Root,
} from "../layout-core";

const StyledHeader = styled(Header)(() => ({
  boxShadow: "0 1px 2px 0 rgba(0, 0, 0, .10)",
  backgroundColor: "#ffffff",
}));

const theme = responsiveFontSizes(
  createTheme({
    palette: {
      primary: {
        main: "rgb(0, 153, 255)",
      },
      background: {
        default: "#fff",
      },
    },
    typography: {
      fontFamily:
        '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol"',
      body1: {
        fontSize: `${15 / 16}rem`,
      },
    },
    components: {
      MuiCssBaseline: {
        styleOverrides: {
          "strong, b": {
            fontWeight: "bold",
          },
        },
      },
    },
  }),
);
// @ts-expect-error theme uses vars in MUI but this layout needs it nullified
theme.vars = null;

export function LayoutV6AppMessenger() {
  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <Root standalone>
        <StyledHeader height="64px" sx={{ position: "relative" }}>
          <Toolbar disableGutters sx={{ flex: "auto" }}>
            <ConversationHead />
          </Toolbar>
        </StyledHeader>
        <EdgeSidebar
          permanentAutoCollapse="md"
          variant={{
            xs: [
              "permanent",
              {
                width: "25cqw",
                collapsedWidth: "80px",
              },
            ],
          }}
        >
          <EdgeSidebarContent>
            <ChatsHeader />
            <Box p={"4px 16px 12px"}>
              <MessengerSearch />
            </Box>
            <ChatList />
          </EdgeSidebarContent>
        </EdgeSidebar>
        <Content>
          <ChatDialog />
          <InsetSidebar position="absolute" width="25cqw">
            <InsetContent>
              <ChatSettings />
            </InsetContent>
          </InsetSidebar>
        </Content>
        <Footer>
          <Container disableGutters>
            <InsetAvoidingView>
              <Box display={"flex"} alignItems={"center"} p={1}>
                <ChatBar />
              </Box>
            </InsetAvoidingView>
          </Container>
        </Footer>
      </Root>
    </ThemeProvider>
  );
}

