      paddingLeft: "16px",
      backgroundColor: "rgba(0,0,0,0.04)",
      margin: "0 8px",
      height: 36,
      fontSize: 13,
    },
  };
  return (
    <>
      <AddCircle sx={styles.icon} />
      {!concise && (
        <>
          <Gif sx={styles.icon} />
          <Note sx={styles.icon} />
          <ImageIcon sx={styles.icon} />
