      <InputBase
        placeholder={"Type a message..."}
        endAdornment={
          <InputAdornment position={"end"}>
            <TagFaces sx={styles.icon} />
          </InputAdornment>
        }
        sx={styles.input}
      />
      <ThumbUp sx={styles.icon} />
    </>
  );
};

export default ChatBar;

