          }),
          "&:hover": {
            "& .ChatListItem-dot": {
              display: "none",
            },
            "& .ChatListItem-responded": {
              display: "none",
            },
            "& .ChatListItem-more": {
              visibility: "visible",
            },
          },
        }}
      >
        <Avatar
          src={avatar}
          sx={{ width: 50, height: 50, marginRight: "12px" }}
        />
