                <Avatar
                  src={avatar}
                  className="ChatListItem-responded"
                  sx={{
                    position: "absolute",
                    top: "50%",
                    left: "50%",
                    transform: "translate(-50%, -50%)",
                    width: 16,
                    height: 16,
                  }}
                />
              )}
